query:
CREATE TABLE `headlines` (
	`id` int AUTO_INCREMENT NOT NULL,
	`userId` int NOT NULL,
	`serviceId` int,
	`campaignId` int,
	`headlineSetId` varchar(50) NOT NULL,
	`formulaType` enum('story','eyebrow','question','authority','urgency') NOT NULL,
	`headline` text NOT NULL,
	`subheadline` text,
	`eyebrow` varchar(255),
	`targetMarket` varchar(255) NOT NULL,
	`pressingProblem` text NOT NULL,
	`desiredOutcome` text NOT NULL,
	`uniqueMechanism` text NOT NULL,
	`rating` int DEFAULT 0,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `headlines_id` PRIMARY KEY(`id`)
);

ALTER TABLE `headlines` ADD CONSTRAINT `headlines_userId_users_id_fk` FOREIGN KEY (`userId`) REFERENCES `users`(`id`) ON DELETE cascade ON UPDATE no action;
ALTER TABLE `headlines` ADD CONSTRAINT `headlines_serviceId_services_id_fk` FOREIGN KEY (`serviceId`) REFERENCES `services`(`id`) ON DELETE set null ON UPDATE no action;
ALTER TABLE `headlines` ADD CONSTRAINT `headlines_campaignId_campaigns_id_fk` FOREIGN KEY (`campaignId`) REFERENCES `campaigns`(`id`) ON DELETE set null ON UPDATE no action;

CREATE INDEX `idx_headlines_userId` ON `headlines` (`userId`);
CREATE INDEX `idx_headlines_campaignId` ON `headlines` (`campaignId`);
CREATE INDEX `idx_headlines_headlineSetId` ON `headlines` (`headlineSetId`);

